// Calculate date range: today-2 (latest GSC) vs today-9 (7 days prior)
const now = new Date();
const currentDate = new Date(now.getTime() - 2 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
const previousDate = new Date(now.getTime() - 9 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
return [{ json: { currentDate, previousDate } }];

// Compare current vs previous week queries for rank drops and CTR anomalies
const currentRaw = $('Fetch Current Queries').first().json;
const previousRaw = $('Fetch Previous Queries').first().json;
const current = Array.isArray(currentRaw) ? currentRaw : (currentRaw.body || currentRaw || []);
const previous = Array.isArray(previousRaw) ? previousRaw : (previousRaw.body || previousRaw || []);
const prevMap = new Map(previous.map(p => [p.query, p]));

const urgentAlerts = [];  // Telegram alert: drop > 3 positions
const warnings = [];      // Lower-priority drops
const ctrAnomalies = [];  // CTR drops > 30%
const disappeared = [];   // Keywords that vanished entirely

// Check for keywords that disappeared (were in previous but not in current)
const currentQueries = new Set(current.map(c => c.query));
for (const prev of previous) {
  if (prev.impressions >= 20 && !currentQueries.has(prev.query)) {
    disappeared.push({
      type: 'disappeared',
      query: prev.query,
      page: prev.page,
      lastPosition: Math.round(prev.position),
      lastImpressions: prev.impressions
    });
  }
}

for (const cur of current) {
  const prev = prevMap.get(cur.query);
  if (!prev) continue;

  const positionDrop = cur.position - prev.position; // positive = worse ranking

  // Urgent: drop > 3 positions AND >= 10 impressions
  if (positionDrop > 3 && prev.impressions >= 10) {
    urgentAlerts.push({
      type: 'urgent_rank_drop',
      query: cur.query,
      page: cur.page,
      oldPosition: Math.round(prev.position * 10) / 10,
      newPosition: Math.round(cur.position * 10) / 10,
      drop: Math.round(positionDrop * 10) / 10,
      impressions: cur.impressions
    });
  }

  // CTR anomaly: >30% drop with stable impressions (both >= 50)
  if (prev.impressions >= 50 && cur.impressions >= 50 && prev.ctr > 0) {
    const ctrDrop = (prev.ctr - cur.ctr) / prev.ctr;
    if (ctrDrop > 0.30) {
      ctrAnomalies.push({
        type: 'ctr_anomaly',
        query: cur.query,
        page: cur.page,
        oldCtr: (prev.ctr * 100).toFixed(1) + '%',
        newCtr: (cur.ctr * 100).toFixed(1) + '%',
        dropPct: (ctrDrop * 100).toFixed(0) + '%',
        impressions: cur.impressions
      });
    }
  }
}

const hasAlerts = urgentAlerts.length > 0 || ctrAnomalies.length > 0 || disappeared.length > 0;

return [{ json: {
  urgentAlerts,
  warnings,
  ctrAnomalies,
  disappeared,
  hasAlerts,
  summary: {
    queriesCompared: current.length,
    urgentCount: urgentAlerts.length,
    warningCount: warnings.length,
    ctrAnomalyCount: ctrAnomalies.length,
    disappearedCount: disappeared.length
  }
}}];

// Build Telegram alert message for rank drops > 3 positions
const data = $json;
const lines = ['\ud83d\udea8 *TG SEO Alert*'];

if (data.urgentAlerts.length > 0) {
  lines.push('');
  lines.push('*Rank Drops (>3 positions):*');
  data.urgentAlerts.slice(0, 8).forEach(a => {
    lines.push(`\u2022 "${a.query}" dropped ${a.drop} pos (${a.oldPosition} \u2192 ${a.newPosition})`);
  });
  if (data.urgentAlerts.length > 8) lines.push(`_+${data.urgentAlerts.length - 8} more_`);
}

if (data.disappeared.length > 0) {
  lines.push('');
  lines.push('*Disappeared Keywords:*');
  data.disappeared.slice(0, 5).forEach(a => {
    lines.push(`\u2022 "${a.query}" was at pos ${a.lastPosition} (${a.lastImpressions} imp)`);
  });
  if (data.disappeared.length > 5) lines.push(`_+${data.disappeared.length - 5} more_`);
}

if (data.ctrAnomalies.length > 0) {
  lines.push('');
  lines.push('*CTR Anomalies:*');
  data.ctrAnomalies.slice(0, 3).forEach(a => {
    lines.push(`\u2022 "${a.query}" CTR ${a.oldCtr} \u2192 ${a.newCtr} (${a.dropPct} drop)`);
  });
  if (data.ctrAnomalies.length > 3) lines.push(`_+${data.ctrAnomalies.length - 3} more_`);
}

lines.push('');
lines.push(`_Compared ${data.summary.queriesCompared} queries (7d window)_`);

return [{ json: { text: lines.join('\n') } }];
